Code:
public int countClumps(int[] nums) {
    int count = 0;
    int current = nums[0];
    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == current) {
            if (i == nums.length - 1 || nums[i] != nums[i+1]) {
                count++;
            }
        } else {
            current = nums[i];
        }
    }
    return count;
}

