public int countClumps(int[] nums) {
    if (nums.length == 0) {
        return 0;
    }

    int clumps = 0;
    int count = 1;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == nums[i - 1]) {
            count++;
        } else {
            if (count >= 2) {
                clumps++;
            }
            count = 1;
        }
    }

    if (count >= 2) {
        clumps++;
    }

    return clumps;
}

