public String alarmClock(int day, boolean vacation) {
    String alarmTime = "";

    // Check if it's a weekday or weekend
    if (day >= 1 && day <= 5) {
        // If it's a weekday, check if we're on vacation
        if (vacation) {
            alarmTime = "10:00";
        } else {
            alarmTime = "7:00";
        }
    } else {
        // If it's a weekend, check if we're on vacation
        if (vacation) {
            alarmTime = "off";
        } else {
            alarmTime = "10:00";
        }
    }

    return alarmTime;
}

