public int[] fix45(int[] nums) {
    int n = nums.length;
    int left = 0, right = 0;

    while (right < n) {
        if (nums[right] == 5) {
            while (left < right && nums[left] != 4) {
                left++;
            }

            if (left == right) {
                int temp = nums[right];
                nums[right] = nums[right + 1];
                nums[right + 1] = temp;
                right++;
            } else {
                left++;
                right++;
            }
        } else {
            right++;
        }
    }

    return nums;
}

public boolean canBalance(int[] nums) {
    int leftSum = 0;
    int rightSum = 0;
    for (int i = 0; i < nums.length; i++) {
        rightSum += nums[i];
    }
    for (int i = 0; i < nums.length; i++) {
        rightSum -= nums[i];
        if (leftSum == rightSum) {
            return true;
        }
        leftSum += nums[i];
    }
    return false;
}

