public boolean canBalance(int[] nums) {
    int totalSum = 0;
    for(int i : nums) {
        totalSum += i;
    }

    if(totalSum % 2 != 0) {
        return false;
    }

    int leftSum = 0;
    for(int i = 0; i < nums.length; i++) {
        leftSum += nums[i];
        if(leftSum == totalSum / 2) {
            return true;
        }
    }

    return false;
}

