        uniqueNumbers.add(a);
        sum += a;
    }

    if (!uniqueNumbers.contains(b)) {
        uniqueNumbers.add(b);
        sum += b;
    }

    if (!uniqueNumbers.contains(c)) {
        uniqueNumbers.add(c);
        sum += c;
    }

    return sum;
}

public int roundSum(int a, int b, int c) {
    return round10(a) + round10(b) + round10(c);
}

public int round10(int num) {
    if (num >= 0) {
        int lastDigit = num % 10;
        if (lastDigit >= 5)
            num = num - lastDigit + 10;
        else if (lastDigit > 0)
            num = num - lastDigit;
    } else {
        num = num % -10;
        num = num - num % 10;
    }
    return num;
}

