Code:
public int makeChocolate(int small, int big, int goal) {
    if (big * 5 > goal) {
        int maxBig = goal / 5;
        if (maxBig > big) maxBig = big;
        goal -= maxBig * 5;
        if (goal > small) return -1;
        return goal;
    } else {
        goal -= big * 5;
        if (goal > small) return -1;
        return goal;
    }
}

public int loneSum(int a, int b, int c) {
  int sum = 0;

  if (a != b && a != c) {
    sum += a;
  }

  if (b != a && b != c) {
    sum += b;
  }

  if (c != a && c != b) {
    sum += c;
  }

  return sum;
}

