public int[] zeroMax(int[] nums) {
    int maxOddIndex = nums.length - 1;
    for (int i = nums.length - 1; i >= 0; i--) {
        if (nums[i] % 2 == 1) {
            maxOddIndex = i;
        } else if (nums[i] == 0 && maxOddIndex > i) {
            nums[i] = nums[maxOddIndex];
        }
    }
    return nums;
}

