    for (int i = 0; i < str.length(); i++) {
        if (str.charAt(i) == 'x') {
            count++;
        } else if (str.charAt(i) == 'y') {
            count--;
        }
        if (count > str.length() - i - 1) {
            return false;
        }
    }
    return count == 0;
}

