public int[] fix45(int[] nums) {
    int n = nums.length;
    int[] output = new int[n];
    int j = 0;
    for (int i = 0; i < n; i++) {
        if (nums[i] != 4) {
            output[j++] = nums[i];
        }
    }
    for (int i = 0; i < n; i++) {
        if (nums[i] == 4) {
            output[j++] = 5;
            output[j++] = 4;
        }
    }
    for (int i = 0; i < n; i++) {
        if (nums[i] == 5) {
            output[j++] = 5;
        }
    }
    return output;
}

