public int countClumps(int[] nums) {
    if (nums.length == 0) {
        return 0;
    }

    int clumps = 0;
    int count = 1;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == nums[i - 1]) {
            count++;
        } else {
            if (count >= 2) {
                clumps++;
            }
            count = 1;
        }
    }

    if (count >= 2) {
        clumps++;
    }

    return clumps;
}

public int[] fix45(int[] nums) {
    int n = nums.length;
    int left = 0, right = 0;

    while (right < n) {
        if (nums[right] == 5) {
            while (left < right && nums[left] != 4) {
                left++;
            }

            if (left == right) {
                int temp = nums[right];
                nums[right] = nums[right + 1];
                nums[right + 1] = temp;
                right++;
            } else {
                left++;
                right++;
            }
        } else {
            right++;
        }
    }

    return nums;
}

public int[] fix45(int[] nums) {
    int n = nums.length;
    int left = 0;
    int right = 0;
    while (right < n) {
        if (nums[right] == 4) {
            while (left < n && nums[left] != 5) {
                left++;
            }
            if (left < n) {
                int temp = nums[left];
                nums[left] = nums[right + 1];
                nums[right + 1] = temp;
                right++;
                left++;
            } else {
                return nums;
            }
        } else {
            right++;
        }
    }
    return nums;
}

