    } else if (a > 21) {
        return b;
    } else if (b > 21) {
        return a;
    } else {
        return (Math.abs(21 - a) < Math.abs(21 - b)) ? a : b;
    }
}

public int[] seriesUp(int n) {
    int length = n * (n + 1) / 2;
    int[] result = new int[length];
    int value = 1;
    int pos = 0;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= i; j++) {
            result[pos++] = value;
        }
        value++;
    }
    return result;
}

