public boolean endOther(String a, String b) {
    a = a.toLowerCase();
    b = b.toLowerCase();
    int len = a.length() < b.length() ? a.length() : b.length();
    for (int i = 0; i < len; i++) {
        if (a.charAt(a.length() - 1 - i) != b.charAt(b.length() - 1 - i)) {
            return false;
        }
    }
    return true;
}

