public int[] zeroMax(int[] nums) {
    int n = nums.length;
    int maxOdd = -1;
    boolean[] isVisited = new boolean[n];
    for (int i = n - 1; i >= 0; i--) {
        if (nums[i] % 2 != 0) {
            maxOdd = nums[i];
        }
        isVisited[i] = (nums[i] == 0) ? (maxOdd > 0) : false;
    }
    for (int i = 0; i < n; i++) {
        if (isVisited[i]) {
            nums[i] = maxOdd;
        }
    }
    return nums;
}

