Code:
public int[] fix45(int[] nums) {
    int i = 0, j = 0;

    while (j < nums.length) {
        if (nums[j] != 4) {
            j++;
            continue;
        }

        while (i < j && nums[i] != 5) {
            i++;
        }

        // Swap 5 with 4 if i < j and i < nums.length
        if (i < j && i < nums.length) {
            int temp = nums[j];
            nums[j] = nums[i];
            nums[i] = temp;
        }

        i = j + 1;
        j++;
    }

    return nums;
}

public int makeChocolate(int small, int big, int goal) {
    if (big * 5 > goal) {
        int maxBig = goal / 5;
        if (maxBig > big) maxBig = big;
        goal -= maxBig * 5;
        if (goal > small) return -1;
        return goal;
    } else {
        goal -= big * 5;
        if (goal > small) return -1;
        return goal;
    }
}

public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int prev = nums[0];

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] % 10 == 0 && nums[i] != prev) {
            prev = nums[i];
        } else if (nums[i] % 10 != 0) {
            nums[i] = prev;
        }
    }

    return nums;
}

public boolean xyzThere(String str) {
    int n = str.length();
    int i = 0;
    while (i < n) {
        if ((i >= 0) && (str.charAt(i) == '.')) {
            i++;
            continue;
        }
        if ((i + 2 < n) && (str.substring(i, i + 3).equals("xyz"))) {
            return true;
        }
        i++;
    }
    return false;
}

