Code:
public int countClumps(int[] nums) {
    if (nums == null || nums.length == 0) {
        return 0;
    }

    int clumpCount = 0;
    int lastNum = nums[0];
    int clumpSize = 1;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == lastNum) {
            clumpSize++;
        } else {
            if (clumpSize >= 2) {
                clumpCount++;
            }
            lastNum = nums[i];
            clumpSize = 1;
        }
    }

    if (clumpSize >= 2) {
        clumpCount++;
    }

    return clumpCount;
}

public int[] zeroMax(int[] nums) {
    int n = nums.length;
    int maxOdd = -1;
    boolean[] isVisited = new boolean[n];
    for (int i = n - 1; i >= 0; i--) {
        if (nums[i] % 2 != 0) {
            maxOdd = nums[i];
        }
        isVisited[i] = (nums[i] == 0) ? (maxOdd > 0) : false;
    }
    for (int i = 0; i < n; i++) {
        if (isVisited[i]) {
            nums[i] = maxOdd;
        }
    }
    return nums;
}

