Code:
public int[] fix45(int[] nums)
{
    int n = nums.length;
    int left = 0, right = n - 1;

    while (left < right)
    {
        if (nums[left] == 4)
        {
            while (right > left && nums[right] != 5)
            {
                right--;
            }
            int temp = nums[left];
            nums[left] = nums[right];
            nums[right] = temp;
            right--;
        }
        left++;
    }
    return nums;
}

