Code:
public boolean twoTwo(int[] nums) {
    int count = 0;
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 2) {
            count++;
            if (i > 0 && nums[i - 1] == 2) {
                count--;
            } else if (i < nums.length - 1 && nums[i + 1] == 2) {
                count--;
            }
        }
    }
    return count == 0;
}

public int makeChocolate(int small, int big, int goal) {
    if (big * 5 >= goal) {
        if ((goal % 5) <= small) {
            return goal % 5;
        } else {
            return -1;
        }
    } else {
        int remainder = goal - (big * 5);
        if (remainder <= small) {
            return remainder;
        } else {
            return -1;
        }
    }
}

