Code:
public int[] fix45(int[] nums) {
    int n = nums.length;
    int left = 0, right = 0;

    while (right < n) {
        if (nums[right] == 5) {
            while (left < right && nums[left] != 4) {
                left++;
            }

            if (left == right) {
                int temp = nums[right];
                nums[right] = nums[right + 1];
                nums[right + 1] = temp;
                right++;
            } else {
                left++;
                right++;
            }
        } else {
            right++;
        }
    }

    return nums;
}

public int[] fix45(int[] nums) {
    int start = 0;
    int end = nums.length - 1;

    while (start < end) {
        // Find first non-4 from start
        while (start < nums.length && nums[start] == 4) start++;
        // Find first non-5 from end
        while (end > 0 && nums[end] == 5) end--;
        // Swap if start is ahead of end
        if (start < end) {
            int temp = nums[start];
            nums[start] = nums[end];
            nums[end] = temp;
        }
    }
    return nums;
}

