        if (nums[i] == nums[clumpStart]) {
            continue;
        } else {
            if (i - clumpStart >= 2) {
                count++;
            }
            clumpStart = i;
        }
    }
    if (nums.length - clumpStart >= 2) {
        count++;
    }
    return count;
}

