public int[] fix45(int[] nums) {
    int i = 0, j = 0;

    while (j < nums.length) {
        if (nums[j] != 4) {
            j++;
            continue;
        }

        while (i < j && nums[i] != 5) {
            i++;
        }

        // Swap 5 with 4 if i < j and i < nums.length
        if (i < j && i < nums.length) {
            int temp = nums[j];
            nums[j] = nums[i];
            nums[i] = temp;
        }

        i = j + 1;
        j++;
    }

    return nums;
}

public int luckySum(int a, int b, int c) {
    int sum = 0;

    // Check if 'a' is 13 and return 0 if true
    if (a != 13) {
        sum += a;
    } else {
        return 0;
    }

    // Check if 'b' is 13 and return sum if true
    if (b != 13) {
        sum += b;
    } else {
        return sum;
    }

    // Check if 'c' is 13 and return sum if true
    if (c != 13) {
        sum += c;
    } else {
        return sum;
    }

    return sum;
}

public String plusOut(String str, String word) {
    String result = "";
    int wordLen = word.length();
    int startIdx = 0;
    while (startIdx <= str.length() - wordLen) {
        int endIdx = startIdx + wordLen;
        if (str.substring(startIdx, endIdx).equals(word)) {
            result += word;
            startIdx = endIdx;
        } else {
            result += "+";
            startIdx++;
        }
    }
    for (int i = startIdx; i < str.length(); i++) {
        result += "+";
    }
    return result;
}

