public int[] tenRun(int[] nums) {
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] % 10 == 0) {
            int j = i + 1;
            while (j < nums.length && nums[j] % 10 != 0) {
                nums[j] = nums[i];
                j++;
            }
        }
    }
    return nums;
}

