public boolean sameEnds(int[] nums, int n) {
    if (n == 0) {
        return true;
    }
    int[] firstN = new int[n];
    int[] lastN = new int[n];

    System.arraycopy(nums, 0, firstN, 0, n);
    System.arraycopy(nums, nums.length - n, lastN, 0, n);

    for (int i = 0; i < n; i++) {
        if (firstN[i] != lastN[i]) {
            return false;
        }
    }

    return true;
}

