public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int prev = nums[0];

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] % 10 == 0 && nums[i] != prev) {
            prev = nums[i];
        } else if (nums[i] % 10 != 0) {
            nums[i] = prev;
        }
    }

    return nums;
}

public int[] fix45(int[] nums) {
    int i = 0, j = 1;
    while (j < nums.length) {
        if (nums[i] == 4 && nums[j] == 5) {
            i++;
            j++;
        } else if (nums[i] == 4 && nums[j] != 5) {
            swap(nums, i, j);
            j++;
        } else {
            i++;
        }
    }
    return nums;
}

private void swap(int[] nums, int i, int j) {
    int temp = nums[i];
    nums[i] = nums[j];
    nums[j] = temp;
}

