        if (str.charAt(i) == 'x') {
            if (hasY) {
                hasY = false;
            } else {
                return false;
            }
        } else if (str.charAt(i) == 'y') {
            lastYIndex = i;
            hasY = true;
        }
    }

    if (hasY) {
        return false;
    }

    return true;
}

