Code:
public int[] fix45(int[] nums) {
    int n = nums.length;
    int left = 0;
    int right = 0;
    while (right < n) {
        if (nums[right] == 4) {
            while (left < n && nums[left] != 5) {
                left++;
            }
            if (left < n) {
                int temp = nums[left];
                nums[left] = nums[right + 1];
                nums[right + 1] = temp;
                right++;
                left++;
            } else {
                return nums;
            }
        } else {
            right++;
        }
    }
    return nums;
}

