Code:
public String atFirst(String str) {
    if (str.isEmpty()) { 
        return "@@"; 
    } else if (str.length() == 1) { 
        return str + "@"; 
    } else if (str.length() > 1) { 
        return str.substring(0, 2); 
    } else { 
        return ""; 
    }
}

public String atFirst(String str) {
    if (str.length() < 1) {
        return "@@";
    } else if (str.length() == 1) {
        return str + "@";
    } else {
        return str.substring(0, 2);
    }
}

