public int[] tenRun(int[] nums) {
    int[] result = new int[nums.length];
    int lastMultipleOfTen = -1;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] % 10 == 0) {
            lastMultipleOfTen = nums[i];
        }
        result[i] = lastMultipleOfTen;
    }
    return result;
}

