public int[] withoutTen(int[] nums) {
    int count = 0; 
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] != 10) {
            nums[i - count] = nums[i];
        } else {
            count++;
        }
    }
    // Fill the remaining elements with 0
    for (int i = nums.length - count; i < nums.length; i++) {
        nums[i] = 0;
    }
    return nums;
}

