public int[] tenRun(int[] nums) {
    ArrayList<Integer> list = new ArrayList<>();
    int lastMultiple = 0;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] % 10 == 0 && nums[i] > lastMultiple) {
            lastMultiple = nums[i];
            list.add(lastMultiple);
        } else {
            list.add(lastMultiple);
        }
    }

    int[] result = new int[list.size()];
    for (int i = 0; i < list.size(); i++) {
        result[i] = list.get(i);
    }

    return result;
}

