public int[] fix45(int[] nums) {
    int countOfFives = 0;
    for(int num : nums) {
        if(num == 5) countOfFives++;
    }

    int[] result = new int[nums.length];
    int i = 0, j = 0;

    while(i < nums.length){
        if(nums[i] == 4){
            if(j < countOfFives){
                result[j] = 5;
                j++;
            }
            result[j] = 4;
            j++;
        } else {
            result[j] = nums[i];
            j++;
        }
        i++;
    }
    return result;
}

