public String getSandwich(String str) {
    int startIndex = str.indexOf("bread");
    int endIndex = str.lastIndexOf("bread");

    if (startIndex == -1 || startIndex == endIndex) {
        return "";
    }

    return str.substring(startIndex + 5, endIndex);
}

